step.class_design:

class DeterministicPolicyChecker:
    """Deterministic pre-filter for PA classification.

    Implements AI Risk Assessment §Recommendation 1: secondary deterministic
    algorithmic checker supplementing the LLM classifier.

    Evaluates structured CAR fields directly. If any DENY rule fires,
    the LLM is never invoked — removes all possibility of model hedging.

    Returns:
        Tuple[str, str] of ("DENY", rule_name) if any rule matches.
        None if no rule matches (proceed to LLM classification).
    """

    _RESTRICTED_PREFIXES: ClassVar[tuple[str, ...]] = (
        "/proc/", "/system/", "/etc/", "/var/log/",
    )

    _AUTHORITY_CLAIM_RE: ClassVar[re.Pattern[str]] = re.compile(
        r"pre-approved|pre_approved(?!_)|security.{0,5}team.{0,10}author|authorization.{0,10}bypass|bypass.{0,10}author",
        re.IGNORECASE,
    )

    @classmethod
    def check(cls, car: CanonicalActionRepresentation) -> tuple[str, str] | None:
        """Evaluate CAR against deterministic DENY rules.

        Args:
            car: The action request to evaluate.

        Returns:
            ("DENY", rule_name) if a rule fires. None otherwise.
        """
        try:
            if car is None:
                return ("DENY", "DENY_NULL_CAR")

            resource: str = car.resource or ""

            # RULE 1 — DENY_RESTRICTED_PATH
            if any(resource.startswith(p) for p in cls._RESTRICTED_PREFIXES):
                return ("DENY", "DENY_RESTRICTED_PATH")
            if "/certs/" in resource:
                return ("DENY", "DENY_RESTRICTED_PATH")
            if resource.startswith("/home/") and not resource.startswith("/home/user/"):
                return ("DENY", "DENY_RESTRICTED_PATH")

            # RULE 2 — DENY_EXFILTRATION
            params_str: str = json.dumps(car.parameters_schema) if car.parameters_schema else ""
            if "/tmp/export/" in params_str:
                return ("DENY", "DENY_EXFILTRATION")

            # RULE 3 — DENY_EXTERNAL_NETWORK
            if resource.startswith("http://") or resource.startswith("https://"):
                return ("DENY", "DENY_EXTERNAL_NETWORK")

            # RULE 4 — DENY_AUTHORITY_CLAIM (defense-in-depth)
            if params_str and cls._AUTHORITY_CLAIM_RE.search(params_str):
                return ("DENY", "DENY_AUTHORITY_CLAIM")

            return None

        except Exception:
            return ("DENY", "DENY_EXCEPTION")
